mapper.select:
SELECT

FROM allocation_info t0
left join allocation_info_detail t1 on t1.allocation_id = t0.id
left join project_info t2 on t1.project_id = t2.id and t2.is_deleted = 0


    AND t0.create_stamp BETWEEN

      #{item}



    AND (t2.affiliated_org IN
          #{item}
      OR

      t2.manage LIKE CONCAT('%',#{item},'%')

    )


    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.allocation_illustrate LIKE CONCAT('%', #{request.allocationIllustrate},'%')


    AND t0.title LIKE CONCAT('%', #{request.title},'%')


    AND t0.flow_state = #{request.flowState}


    AND t0.is_deleted = #{request.isDeleted}


GROUP BY t0.id


    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
